class Handler(BaseHTTPRequestHandler):
    def log_message(self, fmt, *args): pass

    def respond(self, data, status=200):
        b = json.dumps(data).encode()
        self.send_response(status)
        self.send_header('Content-Type','application/json')
        self.send_header('Content-Length',str(len(b)))
        self.send_header('Access-Control-Allow-Origin','*')
        self.end_headers()
        self.wfile.write(b)

    def do_OPTIONS(self):
        self.send_response(200)
        self.send_header('Access-Control-Allow-Origin','*')
        self.send_header('Access-Control-Allow-Methods','GET,POST,OPTIONS')
        self.send_header('Access-Control-Allow-Headers','Content-Type,Authorization,apikey')
        self.end_headers()

    def do_GET(self):
        # Progress page
        if self.path.startswith('/progress/'):
            token = self.path.split('/progress/')[-1].split('?')[0].strip()
            if token:
                _sk = os.environ.get('SUPABASE_SERVICE_KEY','')
                try:
                    import urllib.request as _ur
                    _req = urllib.request.Request(
                        SUPA_URL+'/rest/v1/torq_client_tokens?select=*,torq_clients(*)&token=eq.'+token+'&limit=1',
                        headers={'apikey':_sk,'Authorization':'Bearer '+_sk,'Accept':'application/json'}
                    )
                    with urllib.request.urlopen(_req,timeout=10) as _r:
                        _rows = json.loads(_r.read())
                        if _rows:
                            _row = _rows[0]
                            _cl = _row.get('torq_clients') or {}
                            _cid = _row.get('client_id','')
                            _creq = urllib.request.Request(
                                SUPA_URL+'/rest/v1/torq_candidates?select=*&client_id=eq.'+_cid+'&order=match_score.desc',
                                headers={'apikey':_sk,'Authorization':'Bearer '+_sk,'Accept':'application/json'}
                            )
                            with urllib.request.urlopen(_creq,timeout=10) as _cr:
                                _cands = json.loads(_cr.read())
                            _html = build_progress_page(_cl, _cands)
                            _b = _html.encode('utf-8')
                            self.send_response(200)
                            self.send_header('Content-Type','text/html; charset=utf-8')
                            self.send_header('Content-Length',str(len(_b)))
                            self.end_headers()
                            self.wfile.write(_b)
                            return
                except Exception as _e:
                    pass
        # Serve Torq app for all other routes
        content = TORQ_HTML_STR.encode('utf-8')
        self.send_response(200)
        self.send_header('Content-Type','text/html; charset=utf-8')
        self.send_header('Content-Length',str(len(content)))
        self.send_header('Access-Control-Allow-Origin','*')
        self.end_headers()
        self.wfile.write(content)

